class MathWordModule(dspy.Module):
    def __init__(self):
        super().__init__()
        self.rlm = dspy.RLM(dspy.Signature('problem: str -> answer: int', 'Solve a math word problem.'), tools=[apply_operation])

    def forward(self, **inputs):
        result = self.rlm(**inputs)
        return dspy.Prediction(answer=result.answer)
